// Auto-generated sitemap for Vercel edge crawling
export default function sitemap() {
  const baseUrl = 'https://sriman-rutvik.vercel.app';

  return [
    { url: baseUrl, lastModified: new Date(), changeFrequency: 'monthly', priority: 1 },
    { url: `${baseUrl}/immersive`, lastModified: new Date(), changeFrequency: 'monthly', priority: 0.9 },
    { url: `${baseUrl}/recruiter`, lastModified: new Date(), changeFrequency: 'monthly', priority: 0.9 },
    { url: `${baseUrl}/certificates`, lastModified: new Date(), changeFrequency: 'monthly', priority: 0.8 },
  ];
}

